type Cell = [number, number];

function key(x: number, y: number): string {
  return `${x},${y}`;
}

function parseKey(k: string): Cell {
  const [xs, ys] = k.split(",");
  return [Number(xs), Number(ys)];
}

export function nextGeneration(cells: Cell[]): Cell[] {
  const live = new Set<string>();
  for (const [x, y] of cells) {
    live.add(key(x, y));
  }

  const neighborCounts = new Map<string, number>();

  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const nk = key(x + dx, y + dy);
        neighborCounts.set(nk, (neighborCounts.get(nk) ?? 0) + 1);
      }
    }
  }

  const next: Cell[] = [];

  for (const [k, count] of neighborCounts) {
    if (live.has(k)) {
      if (count === 2 || count === 3) {
        next.push(parseKey(k));
      }
    } else {
      if (count === 3) {
        next.push(parseKey(k));
      }
    }
  }

  // Handle live cells with zero neighbors (they die, no entry in neighborCounts)
  // They are already excluded since they wouldn't appear in next.

  return next;
}

